import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"前门大街","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/qianmen.md","filePath":"landmarks/qianmen.md","lastUpdated":1784712887000}'),n={name:"landmarks/qianmen.md"};function d(s,t,i,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="前门大街" tabindex="-1">前门大街 <a class="header-anchor" href="#前门大街" aria-label="Permalink to &quot;前门大街&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1542079668-197625d11054?w=1200" alt="前门大街"></p><blockquote><p>&quot;老北京商业的缩影，百年老字号的聚集地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>前门大街位于北京市中轴线上，北起正阳门（前门），南至珠市口，全长845米。前门大街是北京最著名的商业街之一，历史悠久，商铺林立，老字号云集，是体验老北京商业文化的绝佳去处。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线前门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区前门大街</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="形成" tabindex="-1">形成 <a class="header-anchor" href="#形成" aria-label="Permalink to &quot;形成&quot;">​</a></h3><p>前门大街形成于明代永乐年间。明成祖迁都北京后，在前门（正阳门）外形成了繁华的商业区。</p><h3 id="清代繁荣" tabindex="-1">清代繁荣 <a class="header-anchor" href="#清代繁荣" aria-label="Permalink to &quot;清代繁荣&quot;">​</a></h3><p>清代，前门大街进入鼎盛时期。由于内城不允许开设商铺，商业活动集中在正阳门外，前门大街成为北京最繁华的商业街。</p><h3 id="民国时期" tabindex="-1">民国时期 <a class="header-anchor" href="#民国时期" aria-label="Permalink to &quot;民国时期&quot;">​</a></h3><p>民国时期，前门大街继续繁荣。电车（铛铛车）的开通使前门大街更加热闹。</p><h3 id="现代改造" tabindex="-1">现代改造 <a class="header-anchor" href="#现代改造" aria-label="Permalink to &quot;现代改造&quot;">​</a></h3><p>2007年，前门大街进行大规模改造，恢复了清末民初的风貌。铛铛车重新开通，老字号重新聚集。</p><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="正阳门" tabindex="-1">正阳门 <a class="header-anchor" href="#正阳门" aria-label="Permalink to &quot;正阳门&quot;">​</a></h3><p>正阳门俗称前门，是明清北京内城的正门，也是北京城最高的城门楼。正阳门由城楼和箭楼组成，是北京城的标志性建筑。</p><h4 id="正阳门城楼" tabindex="-1">正阳门城楼 <a class="header-anchor" href="#正阳门城楼" aria-label="Permalink to &quot;正阳门城楼&quot;">​</a></h4><ul><li><strong>高度</strong>：约40米</li><li><strong>结构</strong>：重檐歇山顶，灰筒瓦绿剪边</li><li><strong>功能</strong>：明清皇帝出巡必经之门</li></ul><h4 id="正阳门箭楼" tabindex="-1">正阳门箭楼 <a class="header-anchor" href="#正阳门箭楼" aria-label="Permalink to &quot;正阳门箭楼&quot;">​</a></h4><p>箭楼位于城楼前方，是防御性建筑。箭楼四面有箭窗，用于射击。</p><h3 id="铛铛车" tabindex="-1">铛铛车 <a class="header-anchor" href="#铛铛车" aria-label="Permalink to &quot;铛铛车&quot;">​</a></h3><p>前门大街上的铛铛车（有轨电车）是旅游观光车，复刻了老北京电车的模样。</p><ul><li><strong>票价</strong>：单程20元</li><li><strong>路线</strong>：前门大街往返</li><li><strong>体验</strong>：叮当作响，复古怀旧</li></ul><h2 id="老字号" tabindex="-1">老字号 <a class="header-anchor" href="#老字号" aria-label="Permalink to &quot;老字号&quot;">​</a></h2><p>前门大街是老字号的聚集地，汇聚了众多百年老店。</p><h3 id="餐饮老字号" tabindex="-1">餐饮老字号 <a class="header-anchor" href="#餐饮老字号" aria-label="Permalink to &quot;餐饮老字号&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">老字号</th><th style="text-align:left;">特色</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全聚德</strong></td><td style="text-align:left;">北京烤鸭</td><td style="text-align:left;">前门大街30号</td></tr><tr><td style="text-align:left;"><strong>都一处</strong></td><td style="text-align:left;">烧麦</td><td style="text-align:left;">前门大街38号</td></tr><tr><td style="text-align:left;"><strong>月盛斋</strong></td><td style="text-align:left;">酱羊肉</td><td style="text-align:left;">前门大街1号</td></tr><tr><td style="text-align:left;"><strong>一条龙</strong></td><td style="text-align:left;">羊肉泡馍</td><td style="text-align:left;">前门大街</td></tr><tr><td style="text-align:left;"><strong>庆丰包子铺</strong></td><td style="text-align:left;">包子</td><td style="text-align:left;">前门大街</td></tr></tbody></table><h3 id="商业老字号" tabindex="-1">商业老字号 <a class="header-anchor" href="#商业老字号" aria-label="Permalink to &quot;商业老字号&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">老字号</th><th style="text-align:left;">特色</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>瑞蚨祥</strong></td><td style="text-align:left;">绸缎</td><td style="text-align:left;">前门大街5号</td></tr><tr><td style="text-align:left;"><strong>内联升</strong></td><td style="text-align:left;">布鞋</td><td style="text-align:left;">前门大街34号</td></tr><tr><td style="text-align:left;"><strong>步瀛斋</strong></td><td style="text-align:left;">布鞋</td><td style="text-align:left;">前门大街</td></tr><tr><td style="text-align:left;"><strong>盛锡福</strong></td><td style="text-align:left;">帽子</td><td style="text-align:left;">前门大街</td></tr><tr><td style="text-align:left;"><strong>广誉远</strong></td><td style="text-align:left;">中药</td><td style="text-align:left;">前门大街</td></tr></tbody></table><h3 id="文化老字号" tabindex="-1">文化老字号 <a class="header-anchor" href="#文化老字号" aria-label="Permalink to &quot;文化老字号&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">老字号</th><th style="text-align:left;">特色</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中国书店</strong></td><td style="text-align:left;">古籍</td><td style="text-align:left;">前门大街</td></tr><tr><td style="text-align:left;"><strong>大观楼</strong></td><td style="text-align:left;">电影院</td><td style="text-align:left;">前门大街</td></tr><tr><td style="text-align:left;"><strong>谦祥益</strong></td><td style="text-align:left;">丝绸</td><td style="text-align:left;">前门大街</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>前门漫步（约2-3小时）</strong>：</p><p>前门地铁站 → 正阳门 → 前门大街（由北向南） → 铛铛车体验 → 大栅栏 → 小吃街</p><p><strong>结合天安门路线（约半天）</strong>：</p><p>天安门广场 → 正阳门 → 前门大街 → 大栅栏 → 午餐（全聚德烤鸭）</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线前门站B口或C口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">前门站，多条线路</td></tr><tr><td style="text-align:left;">铛铛车</td><td style="text-align:left;">前门大街观光</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>铛铛车体验</strong>：推荐乘坐铛铛车，复古有趣</li><li><strong>老字号购物</strong>：可以购买布鞋、丝绸等特产</li><li><strong>美食推荐</strong>：全聚德烤鸭、都一处烧麦</li><li><strong>夜景欣赏</strong>：夜景灯光漂亮，适合拍照</li><li><strong>避开高峰</strong>：周末人很多，建议工作日前往</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">世界最大城市广场</td></tr><tr><td style="text-align:left;">大栅栏</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">鲜鱼口</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">小吃街</td></tr><tr><td style="text-align:left;">国家博物馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">国家级博物馆</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">明清皇宫</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>前门大街是北京商业文化的缩影，老字号承载着北京人的记忆和情感。在这里，你可以品尝正宗的北京烤鸭，购买传统的老北京布鞋，感受老北京的商业氛围。</p><p>&quot;头顶马聚源，脚踩内联升，身穿瑞蚨祥，腰缠四大恒&quot;，这句老话形象地描述了老北京人对前门的印象。</p><hr><p><strong>📍 地址</strong>：北京市东城区前门大街 <strong>🚇 地铁</strong>：2号线前门站</p>',51)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
